/**
 * Advanced Example Module Hooks
 *
 * Hook system demonstrating E-Menum hook patterns.
 * This file showcases:
 * - Hook type definitions
 * - Hook manager implementation
 * - Before/after hook execution
 * - Hook priority ordering
 * - Error handling in hooks
 *
 * @module modules/_examples/advanced-example/hooks
 *
 * @example
 * ```typescript
 * import {
 *   HookManager,
 *   createHookManager,
 * } from '@/modules/_examples/advanced-example/advanced-example.hooks';
 *
 * const hooks = createHookManager();
 *
 * // Register a hook
 * hooks.register('beforeExampleCreate', async (context) => {
 *   console.log('Creating example:', context.data.name);
 * });
 *
 * // Execute hooks
 * await hooks.execute('beforeExampleCreate', { data, organizationId, userId });
 * ```
 */

import type {
  BeforeCreateContext,
  AfterCreateContext,
  BeforeUpdateContext,
  AfterUpdateContext,
  BeforeDeleteContext,
  AfterDeleteContext,
  ProcessContext,
} from '@/modules/_examples/advanced-example/advanced-example.types';

// -----------------------------------------------------------------------------
// Hook Types
// -----------------------------------------------------------------------------

/**
 * Hook names
 */
export type HookName =
  | 'beforeExampleCreate'
  | 'afterExampleCreate'
  | 'beforeExampleUpdate'
  | 'afterExampleUpdate'
  | 'beforeExampleDelete'
  | 'afterExampleDelete'
  | 'onExampleProcess'
  | 'beforeStatusChange'
  | 'afterStatusChange'
  | 'onValidate';

/**
 * Hook context map
 */
export interface HookContextMap {
  beforeExampleCreate: BeforeCreateContext;
  afterExampleCreate: AfterCreateContext;
  beforeExampleUpdate: BeforeUpdateContext;
  afterExampleUpdate: AfterUpdateContext;
  beforeExampleDelete: BeforeDeleteContext;
  afterExampleDelete: AfterDeleteContext;
  onExampleProcess: ProcessContext;
  beforeStatusChange: {
    exampleId: string;
    organizationId: string;
    currentStatus: string;
    newStatus: string;
    userId?: string;
  };
  afterStatusChange: {
    exampleId: string;
    organizationId: string;
    previousStatus: string;
    newStatus: string;
    userId?: string;
  };
  onValidate: {
    data: unknown;
    organizationId: string;
    operation: 'create' | 'update';
  };
}

/**
 * Hook handler function type
 */
export type HookHandler<T extends HookName> = (
  context: HookContextMap[T]
) => Promise<void> | void;

/**
 * Hook registration with priority
 */
export interface HookRegistration<T extends HookName> {
  /** Handler function */
  handler: HookHandler<T>;
  /** Priority (lower = runs first) */
  priority: number;
  /** Hook identifier */
  id: string;
  /** Whether to continue on error */
  continueOnError?: boolean;
}

/**
 * Hook execution result
 */
export interface HookExecutionResult {
  /** Hook name executed */
  hookName: HookName;
  /** Number of handlers executed */
  handlersExecuted: number;
  /** Execution duration in ms */
  duration: number;
  /** Errors that occurred */
  errors: Array<{ handlerId: string; error: Error }>;
  /** Whether all handlers succeeded */
  success: boolean;
}

// -----------------------------------------------------------------------------
// Hook Manager
// -----------------------------------------------------------------------------

/**
 * Hook manager interface
 */
export interface HookManager {
  /**
   * Registers a hook handler.
   *
   * @param hookName - Name of the hook
   * @param handler - Handler function
   * @param options - Registration options
   * @returns Handler ID for unregistration
   */
  register<T extends HookName>(
    hookName: T,
    handler: HookHandler<T>,
    options?: { priority?: number; id?: string; continueOnError?: boolean }
  ): string;

  /**
   * Unregisters a hook handler.
   *
   * @param hookName - Name of the hook
   * @param handlerId - Handler ID
   * @returns True if handler was removed
   */
  unregister(hookName: HookName, handlerId: string): boolean;

  /**
   * Executes all handlers for a hook.
   *
   * @param hookName - Name of the hook
   * @param context - Context to pass to handlers
   * @returns Execution result
   */
  execute<T extends HookName>(
    hookName: T,
    context: HookContextMap[T]
  ): Promise<HookExecutionResult>;

  /**
   * Gets all registered handlers for a hook.
   *
   * @param hookName - Name of the hook
   * @returns Array of registrations
   */
  getHandlers<T extends HookName>(hookName: T): HookRegistration<T>[];

  /**
   * Clears all handlers for a hook.
   *
   * @param hookName - Name of the hook
   */
  clear(hookName: HookName): void;

  /**
   * Clears all handlers.
   */
  clearAll(): void;
}

/**
 * Creates a new hook manager instance.
 *
 * @returns Hook manager
 *
 * @example
 * ```typescript
 * const hooks = createHookManager();
 *
 * // Register hooks
 * hooks.register('beforeExampleCreate', async (ctx) => {
 *   // Validate data
 *   if (!ctx.data.name) {
 *     throw new Error('Name is required');
 *   }
 * }, { priority: 10 });
 *
 * hooks.register('afterExampleCreate', async (ctx) => {
 *   // Send notification
 *   console.log('Example created:', ctx.example.id);
 * });
 *
 * // Execute hooks
 * const result = await hooks.execute('beforeExampleCreate', {
 *   data: { name: 'Test' },
 *   organizationId: 'org_123',
 * });
 * ```
 */
export function createHookManager(): HookManager {
  // Store registrations by hook name
  const registrations = new Map<HookName, Map<string, HookRegistration<HookName>>>();

  // Counter for generating unique IDs
  let idCounter = 0;

  /**
   * Generates a unique handler ID.
   */
  function generateId(): string {
    idCounter++;
    return `hook_${Date.now()}_${idCounter}`;
  }

  /**
   * Gets or creates the registration map for a hook.
   */
  function getRegistrationMap(hookName: HookName): Map<string, HookRegistration<HookName>> {
    let map = registrations.get(hookName);
    if (!map) {
      map = new Map();
      registrations.set(hookName, map);
    }
    return map;
  }

  return {
    register<T extends HookName>(
      hookName: T,
      handler: HookHandler<T>,
      options: { priority?: number; id?: string; continueOnError?: boolean } = {}
    ): string {
      const id = options.id || generateId();
      const registration: HookRegistration<T> = {
        handler,
        priority: options.priority ?? 100,
        id,
        continueOnError: options.continueOnError ?? false,
      };

      const map = getRegistrationMap(hookName);
      map.set(id, registration as HookRegistration<HookName>);

      return id;
    },

    unregister(hookName: HookName, handlerId: string): boolean {
      const map = registrations.get(hookName);
      if (!map) return false;
      return map.delete(handlerId);
    },

    async execute<T extends HookName>(
      hookName: T,
      context: HookContextMap[T]
    ): Promise<HookExecutionResult> {
      const startTime = Date.now();
      const errors: Array<{ handlerId: string; error: Error }> = [];
      let handlersExecuted = 0;

      const map = registrations.get(hookName);
      if (!map || map.size === 0) {
        return {
          hookName,
          handlersExecuted: 0,
          duration: 0,
          errors: [],
          success: true,
        };
      }

      // Sort handlers by priority
      const sortedHandlers = Array.from(map.values()).sort(
        (a, b) => a.priority - b.priority
      );

      // Execute handlers in order
      for (const registration of sortedHandlers) {
        try {
          await (registration.handler as HookHandler<T>)(context);
          handlersExecuted++;
        } catch (error) {
          const errorObj = error instanceof Error ? error : new Error(String(error));
          errors.push({ handlerId: registration.id, error: errorObj });

          // Stop execution if not configured to continue on error
          if (!registration.continueOnError) {
            break;
          }
        }
      }

      return {
        hookName,
        handlersExecuted,
        duration: Date.now() - startTime,
        errors,
        success: errors.length === 0,
      };
    },

    getHandlers<T extends HookName>(hookName: T): HookRegistration<T>[] {
      const map = registrations.get(hookName);
      if (!map) return [];
      return Array.from(map.values()) as HookRegistration<T>[];
    },

    clear(hookName: HookName): void {
      registrations.delete(hookName);
    },

    clearAll(): void {
      registrations.clear();
    },
  };
}

// -----------------------------------------------------------------------------
// Default Hook Manager Instance
// -----------------------------------------------------------------------------

/**
 * Default hook manager instance for the module.
 * Can be used directly or replaced with a custom instance.
 */
export const defaultHookManager = createHookManager();

// -----------------------------------------------------------------------------
// Hook Decorator (for classes)
// -----------------------------------------------------------------------------

/**
 * Decorator to register a method as a hook handler.
 *
 * @param hookName - Name of the hook
 * @param options - Registration options
 *
 * @example
 * ```typescript
 * class MyPlugin {
 *   @Hook('beforeExampleCreate', { priority: 10 })
 *   async validateCreate(context: BeforeCreateContext) {
 *     // Validation logic
 *   }
 *
 *   @Hook('afterExampleCreate')
 *   async notifyCreate(context: AfterCreateContext) {
 *     // Notification logic
 *   }
 * }
 * ```
 */
export function Hook<T extends HookName>(
  hookName: T,
  options?: { priority?: number; continueOnError?: boolean }
) {
  return function (
    _target: unknown,
    propertyKey: string,
    descriptor: PropertyDescriptor
  ) {
    const originalMethod = descriptor.value;

    // Register the hook on class instantiation
    // This is a simplified decorator - in production, you'd use a proper DI container
    descriptor.value = function (this: unknown, ...args: unknown[]) {
      // Register the hook if not already registered
      const handlerId = `${(this as object).constructor.name}_${propertyKey}`;
      const existingHandlers = defaultHookManager.getHandlers(hookName);
      const alreadyRegistered = existingHandlers.some((h) => h.id === handlerId);

      if (!alreadyRegistered) {
        defaultHookManager.register(
          hookName,
          originalMethod.bind(this) as HookHandler<T>,
          { ...options, id: handlerId }
        );
      }

      return originalMethod.apply(this, args);
    };

    return descriptor;
  };
}

// -----------------------------------------------------------------------------
// Pre-defined Hook Chains
// -----------------------------------------------------------------------------

/**
 * Common hook chain for CRUD operations.
 */
export const CRUD_HOOKS: Record<string, HookName[]> = {
  create: ['onValidate', 'beforeExampleCreate', 'afterExampleCreate'],
  update: ['onValidate', 'beforeExampleUpdate', 'afterExampleUpdate'],
  delete: ['beforeExampleDelete', 'afterExampleDelete'],
};

/**
 * Executes a chain of hooks in sequence.
 *
 * @param hookManager - Hook manager instance
 * @param hookNames - Array of hook names to execute
 * @param context - Context to pass (must be compatible with all hooks)
 * @returns Combined execution results
 */
export async function executeHookChain<T extends HookName>(
  hookManager: HookManager,
  hookNames: T[],
  context: HookContextMap[T]
): Promise<HookExecutionResult[]> {
  const results: HookExecutionResult[] = [];

  for (const hookName of hookNames) {
    const result = await hookManager.execute(hookName, context);
    results.push(result);

    // Stop chain if hook failed
    if (!result.success) {
      break;
    }
  }

  return results;
}

// -----------------------------------------------------------------------------
// Export All
// -----------------------------------------------------------------------------

export type {
  BeforeCreateContext,
  AfterCreateContext,
  BeforeUpdateContext,
  AfterUpdateContext,
  BeforeDeleteContext,
  AfterDeleteContext,
  ProcessContext,
};
